module top_module(
    input wire clk,
    input wire reset,
    output wire [3:0] count
);reg [3:0] invalid_count;

always @(posedge clk) begin
    if (reset) begin
        invalid_count <= 4'b0;
    end else begin
        invalid_count <= invalid_count + 1;
    end
end

assign count = invalid_count;

endmodule
